// Alimentacion GRADUAL de OcasionPlus: procesa un lote de paginas por ejecucion,
// avanzando un cursor persistente (1..678, ~13.5k coches).
// OJO: la pagina 1 es la URL base; ?page=1 devuelve 404, por eso construimos la url aqui.
const BASE = 'https://www.ocasionplus.com/coches-segunda-mano';
const MAX_PAGE = 678;
const PAGES_PER_RUN = 40;
const store = $getWorkflowStaticData('global');
let cursor = Number(store.opPage || 1);
if (!(cursor >= 1) || cursor > MAX_PAGE) cursor = 1;
const out = [];
for (let i = 0; i < PAGES_PER_RUN; i++) {
  let p = cursor + i;
  if (p > MAX_PAGE) p = ((p - 1) % MAX_PAGE) + 1;
  out.push({ json: { page: p, url: p === 1 ? BASE : BASE + '?page=' + p } });
}
let next = cursor + PAGES_PER_RUN;
if (next > MAX_PAGE) next = ((next - 1) % MAX_PAGE) + 1;
store.opPage = next;
return out;

// OcasionPlus - transform: HTML pagina -> JSON-LD ItemList (Vehicle) -> UPSERT
const httpOut = $input.item.json;
const html = typeof httpOut === 'string' ? httpOut : String(httpOut.data || httpOut.body || '');
let items = [];
const blocks = [...html.matchAll(/<script[^>]*application\/ld\+json[^>]*>([\s\S]*?)<\/script>/gi)].map(m => m[1].trim());
for (const b of blocks) {
  try {
    const j = JSON.parse(b);
    const arr = Array.isArray(j) ? j : (j['@graph'] || [j]);
    for (const o of arr) {
      if (o && o['@type'] === 'ItemList' && Array.isArray(o.itemListElement)) {
        for (const el of o.itemListElement) { const it = el.item || el; if (it && (it['@type'] === 'Vehicle' || it['@type'] === 'Car' || it['@type'] === 'Product')) items.push(it); }
      }
    }
  } catch (e) {}
}
if (!items.length) return [{ json: { sql: null, count: 0 } }];
function esc(v){ if(v===null||v===undefined) return 'NULL'; if(typeof v==='number') return isNaN(v)?'NULL':String(v); return "'"+String(v).replace(/'/g,"''")+"'"; }
function num(s){ const n=parseInt(String(s).replace(/[^0-9]/g,''),10); return isNaN(n)?null:n; }
function reEsc(s){ return s.replace(/[.*+?^${}()|[\]\\]/g,'\\$&'); }
function normGear(r){ const s=String(r||'').toLowerCase(); if(s.indexOf('auto')!==-1) return 'Automatica'; if(s.indexOf('manual')!==-1) return 'Manual'; return ''; }
function normFuel(f){ const s=String(f||'').toLowerCase();
  if(/el\u00e9ctric|electric/.test(s)) return 'El\u00e9ctrico';
  if(/h\u00edbrid|hibrid|phev|hev/.test(s)) return 'H\u00edbrido';
  if(/di\u00e9sel|diesel/.test(s)) return 'Diesel';
  if(/gasolina/.test(s)) return 'Gasolina';
  if(/glp/.test(s)) return 'GLP';
  if(/gnc|gas natural/.test(s)) return 'GNC';
  return String(f||''); }
const rows = [];
for (const it of items) {
  const off = it.offers || {};
  const url = off.url || it.url || '';
  const idm = String(url).match(/-([a-z0-9]+)\/?$/i);
  if (!idm) continue;
  const id = 'op_' + idm[1];
  const brand = (it.brand && it.brand.name) || it.manufacturer || '';
  const shortName = it.name || '';
  const full = it.model || shortName;
  let model = shortName;
  if (brand) model = model.replace(new RegExp(reEsc(brand), 'i'), '');
  model = model.replace(/\s+/g, ' ').trim();
  let version = full;
  if (shortName) version = version.replace(new RegExp(reEsc(shortName), 'i'), '');
  version = version.replace(/\s+/g, ' ').trim();
  const title = full;
  const year = it.productionDate ? (parseInt(String(it.productionDate), 10) || null) : null;
  const mileage = (it.mileageFromOdometer && it.mileageFromOdometer.value != null) ? num(it.mileageFromOdometer.value) : null;
  const price = off.price != null ? num(off.price) : null;
  const transmission = normGear(it.vehicleTransmission);
  const fuel = normFuel(it.fuelType);
  let cv = null; { const m = full.match(/(\d+)\s*CV/i); if (m) cv = parseInt(m[1], 10); }
  let seats = null; { const m = full.match(/(\d+)\s*Plazas/i); if (m) seats = parseInt(m[1], 10); }
  const imgs = it.image ? (Array.isArray(it.image) ? it.image : [it.image]) : [];
  const imageUrl = imgs[0] || '';
  const imagesJson = JSON.stringify(imgs.slice(0, 15)).replace(/'/g, "''");
  const rawPayload = JSON.stringify(it).replace(/'/g, "''");
  const row = '(' +
    esc(id) + ", 'ocasionplus', " + esc(url) + ', ' + esc(title) + ', ' + esc(brand) + ', ' + esc(model) + ', ' + esc(version) + ', ' +
    (year!=null?String(year):'NULL') + ', ' + (mileage!=null?String(mileage):'NULL') + ', ' + (price!=null?String(price):'NULL') + ', ' +
    esc(fuel) + ', ' + esc(transmission) + ', ' + esc(imageUrl) + ", '" + imagesJson + "', " +
    (cv!=null?String(cv):'NULL') + ', ' + (seats!=null?String(seats):'NULL') + ", 'profesional', 'compra', '" + rawPayload + "', NOW(), NOW(), NOW()" +
  ')';
  rows.push(row);
}
if (!rows.length) return [{ json: { sql: null, count: 0 } }];
const cols = 'id, portal, url, title, brand, model, version, year, mileage, price, fuel, transmission, image_url, images, power_cv, seats, seller_type, listing_type, raw_payload, first_seen_at, scraped_at, last_seen_at';
const onConflict = 'ON CONFLICT (id) DO UPDATE SET url=EXCLUDED.url, title=EXCLUDED.title, price=EXCLUDED.price, mileage=EXCLUDED.mileage, ' +
  "image_url=COALESCE(NULLIF(moveadvisor_market_offers.image_url,''), EXCLUDED.image_url), " +
  "images=COALESCE(NULLIF(moveadvisor_market_offers.images,''), EXCLUDED.images), " +
  'power_cv=COALESCE(EXCLUDED.power_cv, moveadvisor_market_offers.power_cv), ' +
  'seats=COALESCE(EXCLUDED.seats, moveadvisor_market_offers.seats), ' +
  'raw_payload=EXCLUDED.raw_payload, last_seen_at=NOW(), updated_at=NOW()';
const sql = 'INSERT INTO moveadvisor_market_offers (' + cols + ') VALUES ' + rows.join(', ') + ' ' + onConflict;
return [{ json: { sql: sql, count: rows.length } }];
